package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.Quote;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetQuotePolicy_Default() throws Exception {
        // Create a new CSVFormat instance via reflection to bypass final fields
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to access the 'quotePolicy' field
        Field quotePolicyField = CSVFormat.class.getDeclaredField("quotePolicy");
        quotePolicyField.setAccessible(true);

        // Remove final modifier from the field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(quotePolicyField, quotePolicyField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        // Set quotePolicy to null
        quotePolicyField.set(format, null);

        Quote quotePolicy = format.getQuotePolicy();
        assertNull(quotePolicy, "Default CSVFormat quotePolicy should be null");
    }

    @Test
    void testGetQuotePolicy_CustomQuotePolicy() {
        Quote customQuotePolicy = Quote.ALL;
        CSVFormat format = CSVFormat.DEFAULT.withQuotePolicy(customQuotePolicy);
        assertEquals(customQuotePolicy, format.getQuotePolicy());
    }

    @Test
    void testGetQuotePolicy_NullQuotePolicy() {
        CSVFormat format = CSVFormat.DEFAULT.withQuotePolicy(null);
        assertNull(format.getQuotePolicy());
    }
}
